import i18n, { useSptTranslation, sptI18n } from '@spotter/i18n-sdk';
import { SpotterMainApp } from '../type';
export type I18nSystemOptions = Parameters<typeof i18n.init>[0];
export async function boostrapI18nSystem(options: I18nSystemOptions, sptApp: SpotterMainApp) {
    i18n.init(options).then(() => {
        sptApp.i18n = i18n;
        window.__SPOTTER_I18N_DATA__ = {
            i18n: i18n,
            useSptTranslation,
            sptI18n
        };
    });
}
